// src/App.js
import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import SignIn from './pages/SignIn.jsx';
import SignUp from './pages/SignUp.jsx';
import Question from './pages/Question.jsx';
import PaperSetPage from './pages/PaperSetPage.jsx';
import AnswerPage from './pages/AnswerPage.jsx'; // Import the new AnswerPage

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<SignIn />} />
        <Route path="/signin" element={<SignIn />} />
        <Route path="/signup" element={<SignUp />} />
        <Route path="/question" element={<Question />} />
        <Route path="/paper-set" element={<PaperSetPage />} />
        <Route path="/exam" element={<AnswerPage />} /> {/* New route for AnswerPage */}
      </Routes>
    </Router>
  );
}

export default App;
